//! C++ wrapper code generation
//!
//! Generates C++ wrapper functions for patterns that CXX can't handle directly:
//! - Constructors (using std::make_unique)
//! - Return-by-value methods
//! - Static methods
//! - Overloaded methods
//!
//! Note: common.hxx is now hand-maintained in opencascade-sys/src/common.hxx,
//! not generated by this module.

use crate::model::{Param, ParsedClass, ParsedFunction, Type};
use crate::resolver::{self, SymbolTable};
use crate::type_mapping;
use heck::ToSnakeCase;
use std::collections::HashSet;
use std::fmt::Write;

/// Check if a type is or contains `const char*` which requires special wrapper handling
fn type_is_cstring(ty: &Type) -> bool {
    match ty {
        Type::ConstPtr(inner) => matches!(inner.as_ref(), Type::Class(name) if name == "char"),
        Type::ConstRef(inner) | Type::MutRef(inner) => type_is_cstring(inner),
        _ => false,
    }
}

/// Check if a parameter type uses an unknown Handle (but allow opaque Class types).
/// This matches the filter used in Rust FFI generation for constructors.
fn param_uses_unknown_handle(ty: &Type, handle_able_classes: &HashSet<String>) -> bool {
    match ty {
        Type::Handle(class_name) => !handle_able_classes.contains(class_name),
        Type::ConstRef(inner) | Type::MutRef(inner) => param_uses_unknown_handle(inner, handle_able_classes),
        _ => false,
    }
}

fn collect_handle_types(classes: &[&ParsedClass]) -> Vec<(String, String)> {
    let mut handles = HashSet::new();

    for class in classes {
        // Add Handle type for classes that are transient (can be wrapped in Handle)
        if class.is_handle_type && !class.has_protected_destructor {
            handles.insert(class.name.clone());
        }

        for method in &class.methods {
            collect_type_handles(&method.return_type, &mut handles);
            for param in &method.params {
                collect_type_handles(&Some(param.ty.clone()), &mut handles);
            }
        }

        for method in &class.static_methods {
            collect_type_handles(&method.return_type, &mut handles);
            for param in &method.params {
                collect_type_handles(&Some(param.ty.clone()), &mut handles);
            }
        }

        for ctor in &class.constructors {
            for param in &ctor.params {
                collect_type_handles(&Some(param.ty.clone()), &mut handles);
            }
        }
    }

    let mut result: Vec<_> = handles
        .into_iter()
        .map(|inner_class| {
            // Use full class name to match Rust side (e.g., HandleGeom2dCurve not HandleCurve)
            let handle_name = format!("Handle{}", inner_class.replace("_", ""));
            (inner_class, handle_name)
        })
        .collect();
    result.sort();
    result
}


/// Collect Handle type inner classes from a type
fn collect_type_handles(ty: &Option<Type>, handles: &mut HashSet<String>) {
    if let Some(ty) = ty {
        match ty {
            Type::Handle(name) => {
                handles.insert(name.clone());
            }
            Type::ConstRef(inner) | Type::MutRef(inner) | Type::ConstPtr(inner) | Type::MutPtr(inner) => {
                collect_type_handles(&Some(inner.as_ref().clone()), handles);
            }
            _ => {}
        }
    }
}

/// Collect headers needed for a type
/// Collect headers needed for a type
fn collect_type_headers(ty: &Option<Type>, headers: &mut HashSet<String>, known_headers: &HashSet<String>) {
    if let Some(ty) = ty {
        // Skip unbindable types (arrays, streams, void pointers, raw pointers, etc.)
        if ty.is_unbindable() {
            return;
        }

        match ty {
            Type::Class(name) => {
                // Skip primitive types that don't have headers
                // Also skip Standard_Address which is defined in Standard_TypeDef.hxx, not its own file
                if matches!(name.as_str(), 
                    "bool" | "char" | "int" | "unsigned" | "float" | "double" | 
                    "void" | "size_t" | "Standard_Address"
                ) {
                    return;
                }
                // Skip nested types (e.g., Message_Messenger::StreamBuffer resolved to just StreamBuffer)
                // OCCT classes follow Module_ClassName pattern, so classes without underscore
                // (except Standard types) are likely nested types that don't have their own header
                if !name.contains('_') && !name.starts_with("Standard") {
                    return;
                }
                // Only include headers that actually exist in the OCCT include directory
                let header = format!("{}.hxx", name);
                if known_headers.is_empty() || known_headers.contains(&header) {
                    headers.insert(header);
                }
            }
            Type::Handle(name) => {
                let header = format!("{}.hxx", name);
                if known_headers.is_empty() || known_headers.contains(&header) {
                    headers.insert(header);
                }
                headers.insert("Standard_Handle.hxx".to_string());
            }
            Type::ConstRef(inner) | Type::MutRef(inner) | Type::ConstPtr(inner) | Type::MutPtr(inner) => {
                collect_type_headers(&Some(inner.as_ref().clone()), headers, known_headers);
            }
            _ => {}
        }
    }
}

// Filter functions - delegate to centralized implementations in resolver module

/// Check if params and return type use any enum types
/// This is a convenience wrapper for the cpp codegen which passes params and return_type separately
fn method_uses_enum(params: &[Param], return_type: &Option<Type>, all_enums: &HashSet<String>) -> bool {
    resolver::params_use_enum(params, all_enums)
        || return_type.as_ref().is_some_and(|t| resolver::type_uses_enum(t, all_enums))
}

fn type_to_cpp_param(ty: &Type) -> String {
    match ty {
        // const char* parameters should accept rust::Str from CXX
        Type::ConstPtr(inner) if matches!(inner.as_ref(), Type::Class(name) if name == "char") => {
            "rust::Str".to_string()
        }
        _ => type_to_cpp(ty),
    }
}

/// Convert parameter to the argument form needed when calling OCCT functions
/// This converts from CXX types to native C++ types (e.g., rust::Str -> const char*)
fn param_to_cpp_arg(param: &Param) -> String {
    match &param.ty {
        // Convert rust::Str to const char* via std::string
        Type::ConstPtr(inner) if matches!(inner.as_ref(), Type::Class(name) if name == "char") => {
            format!("std::string({}).c_str()", param.name)
        }
        _ => param.name.clone(),
    }
}

/// Convert our Type to C++ type string
fn type_to_cpp(ty: &Type) -> String {
    match ty {
        Type::Void => "void".to_string(),
        Type::Bool => "Standard_Boolean".to_string(),
        Type::I32 => "Standard_Integer".to_string(),
        Type::U32 => "unsigned int".to_string(),
        Type::I64 => "long".to_string(),
        Type::U64 => "unsigned long long".to_string(),
        Type::Usize => "size_t".to_string(),
        Type::F32 => "float".to_string(),
        Type::F64 => "Standard_Real".to_string(),
        Type::ConstRef(inner) => format!("const {}&", type_to_cpp(inner)),
        Type::MutRef(inner) => format!("{}&", type_to_cpp(inner)),
        Type::RValueRef(inner) => format!("{}&&", type_to_cpp(inner)),
        Type::ConstPtr(inner) => format!("const {}*", type_to_cpp(inner)),
        Type::MutPtr(inner) => format!("{}*", type_to_cpp(inner)),
        Type::Handle(name) => format!("opencascade::handle<{}>", name),
        Type::Class(name) => name.clone(),
    }
}

/// Convert a resolved type to C++ parameter type (using CXX types like rust::Str)
fn resolved_type_to_cpp_param(ty: &resolver::ResolvedType) -> String {
    // Check if this is a const char* type (needs rust::Str)
    if ty.cpp_type == "const char*" {
        return "rust::Str".to_string();
    }
    ty.cpp_type.clone()
}

/// Convert a resolved parameter to the argument form needed when calling OCCT functions
fn resolved_param_to_cpp_arg(param: &resolver::ResolvedParam) -> String {
    // Check if this is a const char* type (needs conversion from rust::Str)
    if param.ty.cpp_type == "const char*" {
        return format!("std::string({}).c_str()", param.name);
    }
    param.name.clone()
}

pub fn generate_unified_wrappers(
    all_classes: &[&ParsedClass],
    all_functions: &[&ParsedFunction],
    collections: &[super::collections::CollectionInfo],
    known_headers: &HashSet<String>,
    symbol_table: &SymbolTable,
) -> String {
    let mut output = String::new();

    // Collect classes that will have Handle<T> declarations generated
    // These are classes that are handle types (inherit from Standard_Transient) 
    // and don't have protected destructors
    let handle_able_classes: HashSet<String> = all_classes
        .iter()
        .filter(|c| c.is_handle_type && !c.has_protected_destructor)
        .map(|c| c.name.clone())
        .collect();

    // Header guard and includes
    writeln!(output, "// Generated by opencascade-binding-generator").unwrap();
    writeln!(output, "// Unified C++ wrappers for all OCCT modules").unwrap();
    writeln!(output).unwrap();
    writeln!(output, "#pragma once").unwrap();
    writeln!(output, "#include \"common.hxx\"").unwrap();
    writeln!(output).unwrap();

    // Collect ALL headers needed
    let headers = collect_all_required_headers(all_classes, known_headers);
    
    for header in &headers {
        writeln!(output, "#include <{}>", header).unwrap();
    }
    writeln!(output).unwrap();

    // Generate Handle typedefs for ALL classes
    let handle_types = collect_handle_types(all_classes);
    if !handle_types.is_empty() {
        writeln!(output, "// Handle type aliases").unwrap();
        for (inner_class, handle_name) in &handle_types {
            writeln!(
                output,
                "typedef opencascade::handle<{}> {};",
                inner_class, handle_name
            )
            .unwrap();
        }
        writeln!(output).unwrap();
    }

    // Generate wrapper functions for ALL classes
    for class in all_classes {
        if class.has_protected_destructor {
            continue;
        }
        generate_unified_class_wrappers(class, &mut output, symbol_table, &handle_able_classes);
    }

    // Generate wrappers for ALL namespace-level free functions
    generate_unified_function_wrappers(all_functions, &mut output, symbol_table, known_headers);

    // Generate collection wrappers
    if !collections.is_empty() {
        output.push_str(&super::collections::generate_unified_cpp_collections(collections));
    }

    output
}

/// Collect ALL OCCT headers needed for all classes
fn collect_all_required_headers(
    classes: &[&ParsedClass],
    known_headers: &HashSet<String>,
) -> Vec<String> {
    let mut headers = HashSet::new();

    for class in classes {
        // Add header for the class itself
        let class_header = format!("{}.hxx", class.name);
        if known_headers.is_empty() || known_headers.contains(&class_header) {
            headers.insert(class_header);
        }

        // Add headers for types used in methods
        for method in &class.methods {
            collect_type_headers(&method.return_type, &mut headers, known_headers);
            for param in &method.params {
                collect_type_headers(&Some(param.ty.clone()), &mut headers, known_headers);
            }
        }

        for method in &class.static_methods {
            collect_type_headers(&method.return_type, &mut headers, known_headers);
            for param in &method.params {
                collect_type_headers(&Some(param.ty.clone()), &mut headers, known_headers);
            }
        }

        for ctor in &class.constructors {
            for param in &ctor.params {
                collect_type_headers(&Some(param.ty.clone()), &mut headers, known_headers);
            }
        }
    }

    let mut result: Vec<_> = headers.into_iter().collect();
    result.sort();
    result
}

/// Generate C++ wrapper functions for a class in unified mode
fn generate_unified_class_wrappers(
    class: &ParsedClass,
    output: &mut String,
    symbol_table: &SymbolTable,
    handle_able_classes: &HashSet<String>,
) {
    writeln!(output, "// ========================").unwrap();
    writeln!(output, "// {} wrappers", class.name).unwrap();
    writeln!(output, "// ========================").unwrap();
    writeln!(output).unwrap();

    // Generate constructor wrappers
    generate_unified_constructor_wrappers(class, output, &symbol_table.all_enum_names, &symbol_table.all_class_names, handle_able_classes);

    // Generate wrappers for methods that return by value
    // Returns the set of used function names
    let wrapper_fn_names = generate_unified_return_by_value_wrappers(class, output, &symbol_table.all_enum_names, &symbol_table.all_class_names, handle_able_classes);

    // Generate wrappers for methods with const char* parameters
    generate_unified_c_string_param_wrappers(class, output, &symbol_table.all_enum_names, &symbol_table.all_class_names, handle_able_classes);

    // Generate wrappers for methods that return const char*
    generate_unified_c_string_return_wrappers(class, output, &symbol_table.all_enum_names, &symbol_table.all_class_names, handle_able_classes);

    // Generate static method wrappers (takes reserved names to avoid conflicts)
    generate_unified_static_method_wrappers(class, output, &symbol_table.all_enum_names, &wrapper_fn_names, &symbol_table.all_class_names, handle_able_classes);

    // Generate upcast wrappers for inheritance
    generate_unified_upcast_wrappers(class, output, symbol_table);

    // Generate to_owned wrapper
    generate_unified_to_owned_wrapper(class, output);

    // Generate to_handle wrapper for transient classes
    generate_unified_to_handle_wrapper(class, output);

    // Generate Handle upcast wrappers
    generate_unified_handle_upcast_wrappers(class, output, symbol_table);

    // Generate wrappers for inherited methods
    generate_unified_inherited_method_wrappers(class, output, symbol_table, &symbol_table.all_class_names, handle_able_classes);

    writeln!(output).unwrap();
}

/// Generate constructor wrappers for unified mode
fn generate_unified_constructor_wrappers(
    class: &ParsedClass,
    output: &mut String,
    all_enum_names: &HashSet<String>,
    _all_class_names: &HashSet<String>,
    handle_able_classes: &HashSet<String>,
) {
    if class.is_abstract {
        return;
    }

    let mut ctor_names: std::collections::HashMap<String, usize> = std::collections::HashMap::new();

    for ctor in &class.constructors {
        if ctor.params.iter().any(|p| matches!(&p.ty, Type::Class(_) | Type::Handle(_))) {
            continue;
        }
        if ctor.has_unbindable_types() {
            continue;
        }
        if method_uses_enum(&ctor.params, &None, all_enum_names) {
            continue;
        }
        // Filter constructors using unknown Handle types (but allow opaque Class types)
        if ctor.params.iter().any(|p| param_uses_unknown_handle(&p.ty, handle_able_classes)) {
            continue;
        }

        let base_suffix = ctor.overload_suffix();
        let suffix = if base_suffix.is_empty() {
            "ctor".to_string()
        } else {
            format!("ctor{}", base_suffix)
        };

        let count = ctor_names.entry(suffix.clone()).or_insert(0);
        *count += 1;
        let final_suffix = if *count > 1 {
            format!("{}_{}", suffix, count)
        } else {
            suffix
        };

        // Full C++ wrapper name (e.g., gp_Pnt_ctor)
        let wrapper_name = format!("{}_{}", class.name, final_suffix);

        let params_cpp: Vec<String> = ctor
            .params
            .iter()
            .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
            .collect();
        let params_str = params_cpp.join(", ");

        let args: Vec<String> = ctor.params.iter().map(param_to_cpp_arg).collect();
        let args_str = args.join(", ");

        writeln!(
            output,
            "inline std::unique_ptr<{}> {}({}) {{",
            class.name, wrapper_name, params_str
        )
        .unwrap();
        writeln!(output, "    return std::make_unique<{}>({});", class.name, args_str).unwrap();
        writeln!(output, "}}").unwrap();
    }
}

/// Generate return-by-value method wrappers for unified mode
/// Returns a set of generated wrapper function names for conflict avoidance
fn generate_unified_return_by_value_wrappers(
    class: &ParsedClass,
    output: &mut String,
    all_enum_names: &HashSet<String>,
    all_class_names: &HashSet<String>,
    handle_able_classes: &HashSet<String>,
) -> HashSet<String> {
    // First, collect all methods that need wrappers
    let wrapper_methods: Vec<&crate::model::Method> = class.methods.iter().filter(|method| {
        // Skip methods that don't return by value
        let returns_by_value = method.return_type.as_ref().is_some_and(|ty| {
            ty.is_class() || ty.is_handle()
        });
        if !returns_by_value {
            return false;
        }
        if method.has_unbindable_types() {
            return false;
        }
        if method.params.iter().any(|p| matches!(&p.ty, Type::Class(_) | Type::Handle(_))) {
            return false;
        }
        if method_uses_enum(&method.params, &method.return_type, all_enum_names) {
            return false;
        }
        if resolver::has_const_mut_return_mismatch(method) {
            return false;
        }
        if resolver::method_needs_explicit_lifetimes(method) {
            return false;
        }
        // Filter methods using unknown classes/handles
        if method.params.iter().any(|p| type_mapping::type_uses_unknown_handle(&p.ty, all_class_names, handle_able_classes)) {
            return false;
        }
        if let Some(ref ret) = method.return_type {
            if type_mapping::type_uses_unknown_handle(ret, all_class_names, handle_able_classes) {
                return false;
            }
        }
        true
    }).collect();

    // Count methods by name to determine which need overload suffixes
    let mut name_counts: std::collections::HashMap<String, usize> = std::collections::HashMap::new();
    for method in &wrapper_methods {
        *name_counts.entry(method.name.clone()).or_insert(0) += 1;
    }

    let mut used_names = HashSet::new();
    
    for method in wrapper_methods {
        let base_name = heck::AsSnakeCase(&method.name).to_string();
        let needs_suffix = name_counts.get(&method.name).copied().unwrap_or(0) > 1;
        let fn_name = if needs_suffix {
            let base_suffix = method.overload_suffix();
            let same_suffix_diff_const = class.methods.iter()
                .filter(|m| m.name == method.name)
                .any(|m| m.overload_suffix() == base_suffix && m.is_const != method.is_const);
            let suffix = if same_suffix_diff_const && !method.is_const {
                format!("{}_mut", base_suffix)
            } else {
                base_suffix
            };
            format!("{}{}", base_name, suffix)
        } else {
            base_name
        };

        // Full wrapper name (e.g., gp_Pnt_translated)
        let wrapper_name = format!("{}_{}", class.name, fn_name);
        used_names.insert(wrapper_name.clone());

        let return_type = method.return_type.as_ref().unwrap();
        let return_cpp = type_to_cpp(return_type);

        // Self parameter
        let self_param = if method.is_const {
            format!("const {}& self_", class.name)
        } else {
            format!("{}& self_", class.name)
        };

        let params_cpp: Vec<String> = method
            .params
            .iter()
            .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
            .collect();
        let all_params = std::iter::once(self_param)
            .chain(params_cpp)
            .collect::<Vec<_>>()
            .join(", ");

        let args: Vec<String> = method.params.iter().map(param_to_cpp_arg).collect();
        let args_str = args.join(", ");

        writeln!(
            output,
            "inline std::unique_ptr<{}> {}({}) {{",
            return_cpp, wrapper_name, all_params
        )
        .unwrap();
        writeln!(
            output,
            "    return std::make_unique<{}>(self_.{}({}));",
            return_cpp, method.name, args_str
        )
        .unwrap();
        writeln!(output, "}}").unwrap();
    }
    
    used_names
}

/// Generate static method wrappers for unified mode
/// `reserved_names` contains function names already used by wrapper methods
fn generate_unified_static_method_wrappers(
    class: &ParsedClass,
    output: &mut String,
    all_enum_names: &HashSet<String>,
    reserved_names: &HashSet<String>,
    all_class_names: &HashSet<String>,
    handle_able_classes: &HashSet<String>,
) {
    // First, collect all bindable static methods
    let static_methods: Vec<&crate::model::StaticMethod> = class.static_methods.iter()
        .filter(|method| {
            if method.has_unbindable_types() {
                return false;
            }
            if method_uses_enum(&method.params, &method.return_type, all_enum_names) {
                return false;
            }
            // Filter methods using unknown classes/handles
            if method.params.iter().any(|p| type_mapping::type_uses_unknown_handle(&p.ty, all_class_names, handle_able_classes)) {
                return false;
            }
            if let Some(ref ret) = method.return_type {
                if type_mapping::type_uses_unknown_handle(ret, all_class_names, handle_able_classes) {
                    return false;
                }
                // Filter methods returning const char* - CXX can't handle direct binding
                if type_is_cstring(ret) {
                    return false;
                }
            }
            true
        })
        .collect();

    // Count methods by name for internal conflict detection
    let mut name_counts: std::collections::HashMap<String, usize> = std::collections::HashMap::new();
    for method in &static_methods {
        *name_counts.entry(method.name.clone()).or_insert(0) += 1;
    }

    for method in static_methods {
        let base_name = heck::AsSnakeCase(&method.name).to_string();
        let has_internal_conflict = name_counts.get(&method.name).copied().unwrap_or(0) > 1;
        
        // Generate candidate function name
        let fn_name = if has_internal_conflict {
            // Multiple static methods with same name - use suffix
            let suffix = method.overload_suffix();
            format!("{}{}", base_name, suffix)
        } else {
            base_name.clone()
        };
        
        // Check if this conflicts with reserved names (from wrapper methods)
        let full_fn_name = format!("{}_{}", class.name, fn_name);
        let final_fn_name = if reserved_names.contains(&full_fn_name) {
            // Conflict with wrapper method - add suffix to distinguish
            let suffix = method.overload_suffix();
            if suffix.is_empty() {
                // No params, add "_static" to distinguish
                format!("{}_static", base_name)
            } else {
                format!("{}{}", base_name, suffix)
            }
        } else {
            fn_name
        };

        let wrapper_name = format!("{}_{}", class.name, final_fn_name);

        let return_type = match &method.return_type {
            Some(ty) => type_to_cpp(ty),
            None => "void".to_string(),
        };

        let needs_unique_ptr = method
            .return_type
            .as_ref()
            .is_some_and(|ty| ty.is_class() || ty.is_handle());

        let params_cpp: Vec<String> = method
            .params
            .iter()
            .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
            .collect();
        let params_str = params_cpp.join(", ");

        let args: Vec<String> = method.params.iter().map(param_to_cpp_arg).collect();
        let args_str = args.join(", ");

        if needs_unique_ptr {
            writeln!(
                output,
                "inline std::unique_ptr<{}> {}({}) {{",
                return_type, wrapper_name, params_str
            )
            .unwrap();
            writeln!(
                output,
                "    return std::make_unique<{}>({}::{}({}));",
                return_type, class.name, method.name, args_str
            )
            .unwrap();
        } else {
            writeln!(
                output,
                "inline {} {}({}) {{",
                return_type, wrapper_name, params_str
            )
            .unwrap();
            writeln!(
                output,
                "    return {}::{}({});",
                class.name, method.name, args_str
            )
            .unwrap();
        }
        writeln!(output, "}}").unwrap();
    }
}

/// Generate upcast wrappers for unified mode
fn generate_unified_upcast_wrappers(
    class: &ParsedClass,
    output: &mut String,
    symbol_table: &SymbolTable,
) {
    let protected_destructor_classes = symbol_table.protected_destructor_class_names();
    let all_ancestors = symbol_table.get_all_ancestors_by_name(&class.name);

    for base_class in all_ancestors {
        if protected_destructor_classes.contains(&base_class) {
            continue;
        }

        // Skip base classes not in our binding set
        if !symbol_table.all_class_names.contains(&base_class) {
            continue;
        }

        // Const upcast
        let fn_name = format!("{}_as_{}", class.name, base_class);
        writeln!(
            output,
            "inline const {}& {}(const {}& self_) {{ return static_cast<const {}&>(self_); }}",
            base_class, fn_name, class.name, base_class
        )
        .unwrap();

        // Mutable upcast
        let fn_name_mut = format!("{}_mut", fn_name);
        writeln!(
            output,
            "inline {}& {}({}& self_) {{ return static_cast<{}&>(self_); }}",
            base_class, fn_name_mut, class.name, base_class
        )
        .unwrap();
    }
}

/// Generate to_owned wrapper for unified mode
fn generate_unified_to_owned_wrapper(class: &ParsedClass, output: &mut String) {
    let copyable_modules = ["TopoDS", "gp", "TopLoc", "Bnd", "GProp"];
    if !copyable_modules.contains(&class.module.as_str())
        || class.has_protected_destructor
        || class.is_abstract
    {
        return;
    }

    let fn_name = format!("{}_to_owned", class.name);
    writeln!(
        output,
        "inline std::unique_ptr<{}> {}(const {}& self_) {{ return std::make_unique<{}>(self_); }}",
        class.name, fn_name, class.name, class.name
    )
    .unwrap();
}

/// Generate to_handle wrapper for unified mode
fn generate_unified_to_handle_wrapper(class: &ParsedClass, output: &mut String) {
    if !class.is_handle_type || class.has_protected_destructor || class.is_abstract {
        return;
    }

    let handle_type_name = format!("Handle{}", class.name.replace("_", ""));
    let fn_name = format!("{}_to_handle", class.name);

    writeln!(
        output,
        "inline std::unique_ptr<{}> {}(std::unique_ptr<{}> obj) {{",
        handle_type_name, fn_name, class.name
    )
    .unwrap();
    writeln!(
        output,
        "    return std::make_unique<{}>(obj.release());",
        handle_type_name
    )
    .unwrap();
    writeln!(output, "}}").unwrap();
}

/// Generate Handle upcast wrappers for unified mode
fn generate_unified_handle_upcast_wrappers(
    class: &ParsedClass,
    output: &mut String,
    symbol_table: &SymbolTable,
) {
    if !class.is_handle_type || class.has_protected_destructor || class.is_abstract {
        return;
    }

    let protected_destructor_classes = symbol_table.protected_destructor_class_names();
    let all_ancestors = symbol_table.get_all_ancestors_by_name(&class.name);

    // Collect handle-able classes (those that will have Handle declarations)
    let handle_able_classes: HashSet<String> = symbol_table.all_class_names
        .iter()
        .filter(|name| {
            if let Some(c) = symbol_table.class_by_name(name) {
                c.is_handle_type && !c.has_protected_destructor
            } else {
                false
            }
        })
        .cloned()
        .collect();

    let transient_bases: Vec<_> = all_ancestors
        .iter()
        .filter(|base| {
            if protected_destructor_classes.contains(*base) {
                return false;
            }
            // Only include bases that will have Handle declarations
            if !handle_able_classes.contains(*base) {
                return false;
            }
            if let Some(base_class) = symbol_table.class_by_name(base) {
                base_class.is_handle_type
            } else {
                false
            }
        })
        .collect();

    for base_class in transient_bases {
        let handle_type_name = format!("Handle{}", class.name.replace("_", ""));
        let base_handle_name = format!("Handle{}", base_class.replace("_", ""));

        let fn_name = format!("{}_to_{}", handle_type_name, base_handle_name);

        writeln!(
            output,
            "inline std::unique_ptr<{}> {}(const {}& self_) {{",
            base_handle_name, fn_name, handle_type_name
        )
        .unwrap();
        writeln!(
            output,
            "    return std::make_unique<{}>(self_);",
            base_handle_name
        )
        .unwrap();
        writeln!(output, "}}").unwrap();
    }
}

/// Generate wrapper functions for instance methods with C string parameters (unified mode)
/// These need wrappers to convert rust::Str to const char*
fn generate_unified_c_string_param_wrappers(
    class: &ParsedClass,
    output: &mut String,
    all_enum_names: &HashSet<String>,
    all_class_names: &HashSet<String>,
    handle_able_classes: &HashSet<String>,
) {
    for method in &class.methods {
        // Only wrap methods that have C string parameters
        let has_c_string_param = method.params.iter().any(|p| p.ty.is_c_string());
        if !has_c_string_param {
            continue;
        }

        // Skip methods with enum types
        if method_uses_enum(&method.params, &method.return_type, all_enum_names) {
            continue;
        }

        // Check if method is already wrapped by generate_unified_return_by_value_wrappers
        let return_type = method.return_type.as_ref();
        let is_already_wrapped = if method.returns_by_value() {
            let return_type_name = match return_type {
                Some(Type::Class(name)) => Some(name.as_str()),
                _ => None,
            };
            let is_enum = return_type_name.map(|n| all_enum_names.contains(n)).unwrap_or(false);
            !is_enum
        } else {
            false
        };

        if is_already_wrapped {
            continue;
        }

        // Skip methods with unbindable types
        if method.has_unbindable_types() {
            continue;
        }

        // Filter methods using unknown classes/handles
        if method.params.iter().any(|p| type_mapping::type_uses_unknown_handle(&p.ty, all_class_names, handle_able_classes)) {
            continue;
        }
        if let Some(ref ret_type) = method.return_type {
            if type_mapping::type_uses_unknown_handle(ret_type, all_class_names, handle_able_classes) {
                continue;
            }
        }

        // Convert method name to snake_case to match Rust FFI naming
        let method_name_snake = method.name.to_snake_case();
        let wrapper_name = format!("{}_{}", class.name, method_name_snake);

        // Self parameter
        let self_param = if method.is_const {
            format!("const {}& self", class.name)
        } else {
            format!("{}& self", class.name)
        };

        // Other parameters - use type_to_cpp_param for CXX-compatible types (e.g., rust::Str)
        let other_params = method
            .params
            .iter()
            .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
            .collect::<Vec<_>>()
            .join(", ");

        let params = if other_params.is_empty() {
            self_param
        } else {
            format!("{}, {}", self_param, other_params)
        };

        // Argument list for method call - convert from CXX types to native C++ types
        let args = method
            .params
            .iter()
            .map(param_to_cpp_arg)
            .collect::<Vec<_>>()
            .join(", ");

        // Determine return type - check if const char* needs rust::String conversion
        let returns_c_string = method.return_type.as_ref().map(|t| t.is_c_string()).unwrap_or(false);
        let return_type_str = if returns_c_string {
            "rust::String".to_string()
        } else {
            match &method.return_type {
                Some(rt) => type_to_cpp(rt),
                None => "void".to_string(),
            }
        };

        // Check if return type is a reference
        let returns_reference = method.return_type.as_ref().map(|t| t.is_reference()).unwrap_or(false);

        if returns_c_string {
            // const char* -> rust::String conversion
            writeln!(
                output,
                "inline rust::String {wrapper_name}({params}) {{"
            )
            .unwrap();
            writeln!(
                output,
                "    return rust::String(self.{method_name}({args}));",
                method_name = method.name,
            )
            .unwrap();
        } else if returns_reference {
            writeln!(
                output,
                "inline {return_type_str} {wrapper_name}({params}) {{"
            )
            .unwrap();
            writeln!(
                output,
                "    return self.{method_name}({args});",
                method_name = method.name,
            )
            .unwrap();
        } else if return_type_str == "void" {
            writeln!(
                output,
                "inline void {wrapper_name}({params}) {{"
            )
            .unwrap();
            writeln!(
                output,
                "    self.{method_name}({args});",
                method_name = method.name,
            )
            .unwrap();
        } else {
            writeln!(
                output,
                "inline {return_type_str} {wrapper_name}({params}) {{"
            )
            .unwrap();
            writeln!(
                output,
                "    return self.{method_name}({args});",
                method_name = method.name,
            )
            .unwrap();
        }
        writeln!(output, "}}").unwrap();
    }
}

/// Generate wrapper functions for instance methods that return const char* (unified mode)
/// These need wrappers to convert const char* to rust::String
fn generate_unified_c_string_return_wrappers(
    class: &ParsedClass,
    output: &mut String,
    all_enum_names: &HashSet<String>,
    all_class_names: &HashSet<String>,
    handle_able_classes: &HashSet<String>,
) {
    for method in &class.methods {
        // Only wrap methods that return const char*
        let returns_c_string = method.return_type.as_ref().map(|t| t.is_c_string()).unwrap_or(false);
        if !returns_c_string {
            continue;
        }

        // Skip methods with enum types
        if method_uses_enum(&method.params, &method.return_type, all_enum_names) {
            continue;
        }

        // Skip if already wrapped by c_string_param_wrappers
        let has_c_string_param = method.params.iter().any(|p| p.ty.is_c_string());
        if has_c_string_param {
            continue;
        }

        // Skip methods with unbindable types
        if method.has_unbindable_types() {
            continue;
        }

        // Filter methods using unknown classes/handles
        if method.params.iter().any(|p| type_mapping::type_uses_unknown_handle(&p.ty, all_class_names, handle_able_classes)) {
            continue;
        }

        // Convert method name to snake_case to match Rust FFI naming
        let method_name_snake = method.name.to_snake_case();
        let wrapper_name = format!("{}_{}", class.name, method_name_snake);

        // Self parameter
        let self_param = if method.is_const {
            format!("const {}& self", class.name)
        } else {
            format!("{}& self", class.name)
        };

        // Other parameters
        let other_params = method
            .params
            .iter()
            .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
            .collect::<Vec<_>>()
            .join(", ");

        let params = if other_params.is_empty() {
            self_param
        } else {
            format!("{}, {}", self_param, other_params)
        };

        // Argument list for method call
        let args = method
            .params
            .iter()
            .map(param_to_cpp_arg)
            .collect::<Vec<_>>()
            .join(", ");

        // Return rust::String by converting from const char*
        writeln!(
            output,
            "inline rust::String {wrapper_name}({params}) {{"
        )
        .unwrap();
        writeln!(
            output,
            "    return rust::String(self.{method_name}({args}));",
            method_name = method.name,
        )
        .unwrap();
        writeln!(output, "}}").unwrap();
    }
}

/// Generate wrapper functions for inherited methods (unified mode)
fn generate_unified_inherited_method_wrappers(
    class: &ParsedClass,
    output: &mut String,
    symbol_table: &SymbolTable,
    _all_class_names: &HashSet<String>,
    _handle_able_classes: &HashSet<String>,
) {
    use std::collections::HashSet;

    // Skip classes with protected destructors
    if class.has_protected_destructor {
        return;
    }

    // Build a set of method names already declared directly on this class
    let existing_method_names: HashSet<String> = class.methods.iter()
        .map(|m| m.name.clone())
        .collect();

    // Track methods we've already added
    let mut seen_methods: HashSet<String> = HashSet::new();

    // Get all ancestors
    let ancestors = symbol_table.get_all_ancestors_by_name(&class.name);

    for ancestor_name in &ancestors {
        if let Some(ancestor_class) = symbol_table.class_by_name(ancestor_name) {
            let ancestor_methods = symbol_table.included_methods(ancestor_class);

            for resolved_method in ancestor_methods {
                // Skip if this class already has a method with this name
                if existing_method_names.contains(&resolved_method.cpp_name) {
                    continue;
                }

                if class.all_method_names.contains(&resolved_method.cpp_name) {
                    continue;
                }

                if seen_methods.contains(&resolved_method.cpp_name) {
                    continue;
                }

                seen_methods.insert(resolved_method.cpp_name.clone());

                // In unified mode, we DON'T skip cross-module types since all types are in one module
                // But we still skip raw pointers
                let uses_raw_pointers = resolved_method.params.iter()
                    .any(|p| p.ty.rust_ffi_type.contains("*const") || p.ty.rust_ffi_type.contains("*mut"))
                    || resolved_method.return_type.as_ref()
                        .map(|rt| rt.rust_ffi_type.contains("*const") || rt.rust_ffi_type.contains("*mut"))
                        .unwrap_or(false);

                if uses_raw_pointers {
                    continue;
                }

                // In unified mode, all classes should be known, so we don't need to filter
                // for unknown types like per-module mode does for cross-module types.
                // The resolver already handles type resolution.

                // Generate the wrapper function
                let wrapper_name = format!("{}_inherited_{}", class.name, resolved_method.cpp_name);

                // Self parameter
                let self_param = if resolved_method.is_const {
                    format!("const {}& self", class.name)
                } else {
                    format!("{}& self", class.name)
                };

                // Other parameters
                let other_params: Vec<String> = resolved_method.params.iter()
                    .map(|p| format!("{} {}", resolved_type_to_cpp_param(&p.ty), p.name))
                    .collect();

                let params = if other_params.is_empty() {
                    self_param
                } else {
                    format!("{}, {}", self_param, other_params.join(", "))
                };

                // Arguments for calling the method
                let args: Vec<String> = resolved_method.params.iter()
                    .map(resolved_param_to_cpp_arg)
                    .collect();
                let args_str = args.join(", ");

                // Return type
                let return_type_cpp = match &resolved_method.return_type {
                    Some(rt) => {
                        if rt.needs_unique_ptr {
                            format!("std::unique_ptr<{}>", rt.cpp_type)
                        } else {
                            rt.cpp_type.clone()
                        }
                    }
                    None => "void".to_string(),
                };

                // Generate the wrapper
                let needs_unique_ptr = resolved_method.return_type.as_ref()
                    .map(|rt| rt.needs_unique_ptr)
                    .unwrap_or(false);

                writeln!(output, "inline {} {}({}) {{", return_type_cpp, wrapper_name, params).unwrap();

                if needs_unique_ptr {
                    let inner_type = resolved_method.return_type.as_ref()
                        .map(|rt| rt.cpp_type.clone())
                        .unwrap_or_else(|| "void".to_string());
                    writeln!(
                        output,
                        "    return std::make_unique<{}>(self.{}({}));",
                        inner_type, resolved_method.cpp_name, args_str
                    ).unwrap();
                } else if resolved_method.return_type.is_some() {
                    writeln!(
                        output,
                        "    return self.{}({});",
                        resolved_method.cpp_name, args_str
                    ).unwrap();
                } else {
                    writeln!(
                        output,
                        "    self.{}({});",
                        resolved_method.cpp_name, args_str
                    ).unwrap();
                }

                writeln!(output, "}}").unwrap();
            }
        }
    }
}

/// Generate wrappers for all namespace-level free functions
fn generate_unified_function_wrappers(
    functions: &[&ParsedFunction],
    output: &mut String,
    symbol_table: &SymbolTable,
    known_headers: &HashSet<String>,
) {
    if functions.is_empty() {
        return;
    }

    // Group functions by namespace
    let mut by_namespace: std::collections::HashMap<String, Vec<&ParsedFunction>> =
        std::collections::HashMap::new();
    for func in functions {
        by_namespace
            .entry(func.namespace.clone())
            .or_default()
            .push(*func);
    }

    for (namespace, namespace_functions) in by_namespace {
        writeln!(output, "// ========================").unwrap();
        writeln!(output, "// {} namespace functions", namespace).unwrap();
        writeln!(output, "// ========================").unwrap();

        // Extra headers for this namespace
        let mut extra_headers: HashSet<String> = HashSet::new();
        for func in &namespace_functions {
            extra_headers.insert(format!("{}.hxx", namespace));
            for param in &func.params {
                collect_type_headers(&Some(param.ty.clone()), &mut extra_headers, known_headers);
            }
            if let Some(ref ret_ty) = func.return_type {
                collect_type_headers(&Some(ret_ty.clone()), &mut extra_headers, known_headers);
            }
        }

        let mut seen_names: std::collections::HashMap<String, usize> =
            std::collections::HashMap::new();

        for func in namespace_functions {
            if func.has_unbindable_types() {
                continue;
            }
            if method_uses_enum(&func.params, &func.return_type, &symbol_table.all_enum_names) {
                continue;
            }

            let base_rust_name = heck::AsSnakeCase(&func.short_name).to_string();
            let is_mut_version = func.params.iter().any(|p| matches!(&p.ty, Type::MutRef(_)));

            let count = seen_names.entry(base_rust_name.clone()).or_insert(0);
            *count += 1;

            let wrapper_name = if *count > 1 {
                let suffix = if is_mut_version {
                    "_mut"
                } else {
                    &format!("_{}", count)
                };
                format!("{}_{}{}", namespace, base_rust_name, suffix)
            } else {
                format!("{}_{}", namespace, base_rust_name)
            };

            let return_type_cpp = match &func.return_type {
                Some(ty) => type_to_cpp(ty),
                None => "void".to_string(),
            };

            let params_cpp: Vec<String> = func
                .params
                .iter()
                .map(|p| format!("{} {}", type_to_cpp_param(&p.ty), p.name))
                .collect();
            let params_str = params_cpp.join(", ");

            let args: Vec<String> = func.params.iter().map(param_to_cpp_arg).collect();
            let args_str = args.join(", ");

            let call = format!("{}::{}({})", namespace, func.short_name, args_str);

            writeln!(
                output,
                "inline {} {}({}) {{ return {}; }}",
                return_type_cpp, wrapper_name, params_str, call
            )
            .unwrap();
        }
        writeln!(output).unwrap();
    }
}

